config.script:
// jornada_avisos (JOR-10 #770) — agente `script` (MACRO). Comportamento = ESTE arquivo (DADO).
//
// DOIS ramos, escolhidos pelo gatilho:
//   - REATIVO (event.event_type == 'atendimento.jornada_fase_recalculada'): avisa "fase avançou"
//     — SÓ em avanço (confere a ORDEM das fases via a capability buscar_fase; fail-open se não achar).
//     ⚠️ Este gatilho nasce DESLIGADO no manifesto (enabled:false) p/ NÃO duplicar com o
//     `stream_consumer_jornada` que já roda no notification-center. Ligar aqui = aposentar lá
//     (notification-center#109).
//   - CRON (sem event_type): varre a capability listar_pendencias_sla e avisa a equipe sobre requisito
//     obrigatório ALÉM DO PRAZO / jornada SEM MOVIMENTO (Fatia 2 — não há evento p/ "nada aconteceu").
//
// Config editável POR-CLÍNICA (sem redeploy) — é aqui que se desliga/restringe/exclui:
//   `alvo`        { tipo:'broadcast' }  ou  { tipo:'papel', papel:'recepcao' }
//   `silenciados` [usernames]  → excluídos do broadcast (o "usuário chato")
//   `sla_dias`    0 = requisito estritamente vencido/hoje; >0 = look-ahead (avisa vencendo)
//   `parado_dias` jornada sem recomputo de fase há N dias
//
// Injetados pelo runtime: event, config, context, call() -> {ok,status_code,body}, log().

var cfg = config || {};
var et = (event && event.event_type) ? String(event.event_type) : '';

function unwrap(r) {
  if (!r || !r.ok) return null;
  var b = r.body;
  return (b && b.data !== undefined) ? b.data : b;
}

// Dispara o aviso de equipe pelo notification-center, respeitando `alvo`/`silenciados`.
// broadcast → a capability notificar (schema PROÍBE campo `broadcast`/`group_id`);
// papel     → a capability notificar_grupo com group_id (targeted).
function notificar(nivel, titulo, texto, icone) {
  var message = { type: nivel, title: titulo, text: texto, icon: icone };
  var alvo = cfg.alvo || {};
  if (alvo.tipo === 'papel' && alvo.papel) {
    return call('notificar_grupo', { type: 'mensagem', message: message, group_id: String(alvo.papel) });
  }
  var payload = { type: 'mensagem', message: message };
  if (cfg.silenciados && cfg.silenciados.length) payload.exclude_users = cfg.silenciados;
  return call('notificar', payload);
}

// ---------------- RAMO REATIVO: fase avançou (nasce DESLIGADO) ----------------
if (et === 'atendimento.jornada_fase_recalculada') {
  var subj = event.subject || {}, safe = event.payload_safe || {};
  var anterior = safe.fase_anterior, atual = safe.fase_atual;
  if (!atual || atual === anterior) return { skip: 'sem_mudanca' };

  var avancou = true; // fail-open: sem ordem confiável, avisa (melhor que engolir avanço real)
  var faseObj = unwrap(call('buscar_fase', { id: subj.jornada_id }));
  if (faseObj && faseObj.fases && faseObj.fases.length) {
    var ordem = {};
    for (var i = 0; i < faseObj.fases.length; i++) { ordem[faseObj.fases[i].key] = faseObj.fases[i].ordem; }
    if (ordem[anterior] !== undefined && ordem[atual] !== undefined) avancou = ordem[atual] > ordem[anterior];
  }
  if (!avancou) return { skip: 'regressao', de: anterior, para: atual };

  notificar('info', 'Jornada — fase avançou', 'A jornada de um paciente avançou de fase.', 'mdi-flag-checkered');
  return { ok: true, ramo: 'reativo', de: anterior, para: atual };
}

// ---------------- RAMO CRON: varredura SLA / parada ----------------
var prazoDias = (cfg.sla_dias !== undefined && cfg.sla_dias !== null) ? cfg.sla_dias : 0;
var paradoDias = (cfg.parado_dias !== undefined && cfg.parado_dias !== null) ? cfg.parado_dias : 7;

var res = unwrap(call('listar_pendencias_sla', { prazo_dias: prazoDias, parado_dias: paradoDias })) || {};
var itens = res.itens || [];
if (!itens.length) { log('jornada_avisos: sem pendências'); return { ok: true, ramo: 'cron', com_pendencia: 0 }; }

var vencidas = 0, paradas = 0;
for (var k = 0; k < itens.length; k++) {
  if (itens[k].requisitos_vencidos && itens[k].requisitos_vencidos.length) vencidas++;
  if (itens[k].parada) paradas++;
}
var partes = [];
if (vencidas) partes.push(vencidas + ' com requisito além do prazo');
if (paradas) partes.push(paradas + ' sem movimento');

// Um resumo por varredura (anti-spam) — a equipe abre o board p/ o detalhe. Sem PII.
notificar('warning', 'Jornadas — atenção',
  itens.length + ' jornada(s) de pacientes precisam de atenção (' + partes.join(', ') + '). Confira o board de jornadas.',
  'mdi-alert');
return { ok: true, ramo: 'cron', com_pendencia: itens.length, vencidas: vencidas, paradas: paradas };
